import "sort"

// ActivitySelection selects the maximum number of non-overlapping activities.
// The input array encodes activities as consecutive pairs [start, finish, ...].
func ActivitySelection(arr []int) int {
	n := len(arr) / 2
	if n == 0 {
		return 0
	}

	type activity struct {
		start, finish int
	}

	activities := make([]activity, n)
	for i := 0; i < n; i++ {
		activities[i] = activity{arr[2*i], arr[2*i+1]}
	}

	sort.Slice(activities, func(i, j int) bool {
		return activities[i].finish < activities[j].finish
	})

	count := 1
	lastFinish := activities[0].finish

	for i := 1; i < n; i++ {
		if activities[i].start >= lastFinish {
			count++
			lastFinish = activities[i].finish
		}
	}

	return count
}

import java.util.Arrays;

public class ActivitySelection {

    public static int activitySelection(int[] arr) {
        int n = arr.length / 2;
        if (n == 0) {
            return 0;
        }

        int[][] activities = new int[n][2];
        for (int i = 0; i < n; i++) {
            activities[i][0] = arr[2 * i];
            activities[i][1] = arr[2 * i + 1];
        }

        Arrays.sort(activities, (a, b) -> Integer.compare(a[1], b[1]));

        int count = 1;
        int lastFinish = activities[0][1];

        for (int i = 1; i < n; i++) {
            if (activities[i][0] >= lastFinish) {
                count++;
                lastFinish = activities[i][1];
            }
        }

        return count;
    }
}

fun activitySelection(arr: IntArray): Int {
    val n = arr.size / 2
    if (n == 0) {
        return 0
    }

    val activities = Array(n) { i -> Pair(arr[2 * i], arr[2 * i + 1]) }
    activities.sortBy { it.second }

    var count = 1
    var lastFinish = activities[0].second

    for (i in 1 until n) {
        if (activities[i].first >= lastFinish) {
            count++
            lastFinish = activities[i].second
        }
    }

    return count
}

def activity_selection(arr: list[int]) -> int:
    n = len(arr) // 2
    if n == 0:
        return 0

    activities = [(arr[2 * i], arr[2 * i + 1]) for i in range(n)]
    activities.sort(key=lambda a: a[1])

    count = 1
    last_finish = activities[0][1]

    for i in range(1, n):
        if activities[i][0] >= last_finish:
            count += 1
            last_finish = activities[i][1]

    return count

pub fn activity_selection(arr: &[i32]) -> i32 {
    let n = arr.len() / 2;
    if n == 0 {
        return 0;
    }

    let mut activities: Vec<(i32, i32)> = (0..n)
        .map(|i| (arr[2 * i], arr[2 * i + 1]))
        .collect();

    activities.sort_by_key(|a| a.1);

    let mut count = 1;
    let mut last_finish = activities[0].1;

    for i in 1..n {
        if activities[i].0 >= last_finish {
            count += 1;
            last_finish = activities[i].1;
        }
    }

    count
}

object ActivitySelection {

  def activitySelection(arr: Array[Int]): Int = {
    val n = arr.length / 2
    if (n == 0) return 0

    val activities = (0 until n).map(i => (arr(2 * i), arr(2 * i + 1))).toArray
    val sorted = activities.sortBy(_._2)

    var count = 1
    var lastFinish = sorted(0)._2

    for (i <- 1 until n) {
      if (sorted(i)._1 >= lastFinish) {
        count += 1
        lastFinish = sorted(i)._2
      }
    }

    count
  }
}

func activitySelection(_ arr: [Int]) -> Int {
    let n = arr.count / 2
    if n == 0 {
        return 0
    }

    var activities: [(start: Int, finish: Int)] = []
    for i in 0..<n {
        activities.append((start: arr[2 * i], finish: arr[2 * i + 1]))
    }

    activities.sort { $0.finish < $1.finish }

    var count = 1
    var lastFinish = activities[0].finish

    for i in 1..<n {
        if activities[i].start >= lastFinish {
            count += 1
            lastFinish = activities[i].finish
        }
    }

    return count
}

export function activitySelection(arr: number[]): number {
    const n = Math.floor(arr.length / 2);
    if (n === 0) {
        return 0;
    }

    const activities: [number, number][] = [];
    for (let i = 0; i < n; i++) {
        activities.push([arr[2 * i], arr[2 * i + 1]]);
    }

    activities.sort((a, b) => a[1] - b[1]);

    let count = 1;
    let lastFinish = activities[0][1];

    for (let i = 1; i < n; i++) {
        if (activities[i][0] >= lastFinish) {
            count++;
            lastFinish = activities[i][1];
        }
    }

    return count;
}
